fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    use std::cmp::Ordering;
    use std::collections::BinaryHeap;

    let n = n as usize;
    let mut adj = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2] as i64;
        let e = edge[3] as i64;
        adj[u].push((v, s, e));
    }

    let mut heap = BinaryHeap::new();
    heap.push((0, 0));

    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;

    while let Some((time, node)) = heap.pop() {
        if node == n - 1 {
            return time;
        }
        if time > dist[node] {
            continue;
        }

        for (neighbor, start, end) in &adj[node] {
            let new_time = if start <= time && time <= end {
                time + 1
            } else {
                std::cmp::max(start, time) + 1
            };

            if new_time < dist[*neighbor] {
                dist[*neighbor] = new_time;
                heap.push((new_time, *neighbor));
            }
        }
    }

    if dist[n - 1] == i64::MAX {
        -1
    } else {
        dist[n - 1]
    }
}
